module accumulator_32bit(
    input               clk     ,
    input               load    ,
    input               clr     ,
    input      [31:0]   data_in ,
    output reg [31:0]   obf_acc_out 
);

always @(posedge clk) begin
    if (clr)
        obf_acc_out <= 32'd0;
    else if (load)
        obf_acc_out <= data_in;
    else
        obf_acc_out <= obf_acc_out + data_in;
end

endmodule
